class Playground {
    async run(inputs) {
        // Read the user input
        const inputString = inputs[0] || 'apple, app, banana';
        const words = inputString.split(',').map(w => w.trim()).filter(w => w.length > 0);

        this.log(`Received input: ${inputString}`);
        this.log(`Building Trie with ${words.length} words...`);
        this.trie.clear();
        await this.await();

        // 1. Insert Words
        for (const word of words) {
             this.log(`Inserting "${word}"...`);
             this.trie.insert(word);
             await this.await();
        }

        this.log('Finished construction.');

        // 2. Demo Search (Automatic)
        if (words.length > 0) {
             const demoWord = words[0];
             this.log(`Demo: Searching for "${demoWord}"...`);
             const found = this.trie.search(demoWord);
             this.log(`Result: ${found}`);
             await this.await();
             this.trie.clearHighlights();

             // Try a prefix that might exist (e.g. "appl" for "apple")
             if (demoWord.length > 1) {
                 const prefix = demoWord.substring(0, demoWord.length - 1);
                 this.log(`Demo: Checking prefix "${prefix}"...`);
                 const starts = this.trie.startsWith(prefix);
                 this.log(`Result: ${starts}`);
                 await this.await();
                 this.trie.clearHighlights();
             }
        }

        this.log('Done.');
    }
}
